const events = items.map(item => item.json);
const timeZone = 'America/Argentina/Buenos_Aires';

const eventosFormateados = events
  .filter(event => event.start && event.end)
  .map(event => {
    const start = new Date(event.start.dateTime || event.start.date);
    const end = new Date(event.end.dateTime || event.end.date);

    const startInTZ = new Date(start.toLocaleString('en-US', { timeZone }));
    const endInTZ = new Date(end.toLocaleString('en-US', { timeZone }));

    const fecha = startInTZ.toLocaleDateString('es-AR');
    const horaInicio = startInTZ.toLocaleTimeString('es-AR', { hour: '2-digit', minute: '2-digit' });
    const horaFin = endInTZ.toLocaleTimeString('es-AR', { hour: '2-digit', minute: '2-digit' });

    return `• ${fecha} de ${horaInicio} a ${horaFin}`;
  });

const mensaje = `Horarios_ocupados:\n${eventosFormateados.join('\n')}`;

return [
  {
    json: {
      Horarios_ocupados: mensaje
    }
  }
];

