// Formatear eventos ocupados del calendario
const events = items.map(item => item.json);
const timeZone = 'America/Bogota';

const eventosFormateados = events
  .filter(event => event.start && event.end)
  .map(event => {
    const start = new Date(event.start.dateTime || event.start.date);
    const end = new Date(event.end.dateTime || event.end.date);

    const startInTZ = new Date(start.toLocaleString('en-US', { timeZone }));
    const endInTZ = new Date(end.toLocaleString('en-US', { timeZone }));

    const fecha = startInTZ.toLocaleDateString('es-CO', { day: '2-digit', month: '2-digit', year: 'numeric' });
    const horaInicio = startInTZ.toLocaleTimeString('es-CO', { hour: '2-digit', minute: '2-digit', hour12: true });
    const horaFin = endInTZ.toLocaleTimeString('es-CO', { hour: '2-digit', minute: '2-digit', hour12: true });

    return `• ${fecha} de ${horaInicio} a ${horaFin}`;
  });

const mensaje = eventosFormateados.length > 0 
  ? `Horarios ocupados:\n${eventosFormateados.join('\n')}`
  : 'No hay horarios ocupados en los próximos 45 días.';

// Obtener fecha y hora actual en Colombia
const now = new Date();
const nowInColombia = new Date(now.toLocaleString('en-US', { timeZone: 'America/Bogota' }));
const fechaActual = nowInColombia.toLocaleDateString('es-CO', { 
  weekday: 'long', 
  day: '2-digit', 
  month: '2-digit', 
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit',
  hour12: true
});

return [
  {
    json: {
      horarios_ocupados: mensaje,
      fecha_actual: fechaActual,
      tipo_cita: $input.item.json.body.tipo_cita || 'consulta_inicial'
    }
  }
];

